const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const KB_DIR = path.join(PROJECT, 'src/data/antennas');

// Read index.json
const indexJson = JSON.parse(fs.readFileSync(path.join(KB_DIR, 'index.json'), 'utf8'));

// Read 3 example KB JSONs for context
const examples = ['half_wave_dipole', 'rectangular_patch', 'vivaldi_tsa'];
const kbExamples = {};
for (const id of examples) {
  const fp = path.join(KB_DIR, `${id}.json`);
  if (fs.existsSync(fp)) kbExamples[id] = JSON.parse(fs.readFileSync(fp, 'utf8'));
}

// Read current source files
const files = {
  'antennaKB.ts': fs.readFileSync(path.join(PROJECT, 'src/lib/antennaKB.ts'), 'utf8'),
  'AntennaForm.tsx': fs.readFileSync(path.join(PROJECT, 'src/components/AntennaForm/AntennaForm.tsx'), 'utf8'),
  'App.tsx': fs.readFileSync(path.join(PROJECT, 'src/App.tsx'), 'utf8'),
  'AntennaViewport.tsx': fs.readFileSync(path.join(PROJECT, 'src/viewport/AntennaViewport.tsx'), 'utf8'),
  'RadiationPatternView.tsx': fs.readFileSync(path.join(PROJECT, 'src/components/RadiationPatternView.tsx'), 'utf8'),
};

return [{
  json: {
    indexJson,
    kbExamples,
    files,
    antennaCount: indexJson.count,
    categories: [...new Set(indexJson.antennas.map(a => a.category))],
  }
}];

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const results = {};

// Collect agent outputs
const agents = [
  { name: 'Gen KB Loader', file: 'src/lib/antennaKB.ts' },
  { name: 'Gen AntennaForm', file: 'src/components/AntennaForm/AntennaForm.tsx' },
  { name: 'Gen Solver', file: 'src/App.tsx' },
  { name: 'Gen Viewport', file: 'src/viewport/AntennaViewport.tsx' },
  { name: 'Gen Radiation', file: 'src/components/RadiationPatternView.tsx' },
];

let filesWritten = 0;
for (const agent of agents) {
  try {
    const output = $(`${agent.name}`).item.json.output || '';
    if (output.includes('LGTM')) {
      results[agent.file] = 'LGTM';
    } else {
      // Extract code block
      const codeMatch = output.match(/```(?:typescript|tsx?)\n([\s\S]*?)```/);
      if (codeMatch) {
        fs.writeFileSync(path.join(PROJECT, agent.file), codeMatch[1]);
        results[agent.file] = 'WRITTEN';
        filesWritten++;
      } else {
        results[agent.file] = 'LGTM (no code block found)';
      }
    }
  } catch (e) {
    results[agent.file] = `ERROR: ${e.message}`;
  }
}

// Run TSC check
let tscResult = '';
try {
  tscResult = execSync('npx tsc --noEmit 2>&1', { cwd: PROJECT, timeout: 60000 }).toString();
  if (!tscResult.trim()) tscResult = 'OK - no errors';
} catch (e) {
  tscResult = e.stdout?.toString() || e.message;
}

// Git commit if TSC passes
let gitResult = '';
if (tscResult.includes('OK - no errors') || !tscResult.includes('error TS')) {
  try {
    execSync('git add -A', { cwd: PROJECT });
    execSync('git commit -m "feat: integrate 31 antenna KB â€” data-driven architecture\n\nReplaced 5 hardcoded types with category-based approach.\nNew antennaKB.ts loads all 31 KB JSONs via import.meta.glob.\nAntennaForm shows optgroup by category with dynamic KB params.\nSolver uses category models: wire/microstrip/broadband/aperture/array/special.\nViewport and RadiationPattern use category-based rendering."', { cwd: PROJECT });
    gitResult = 'Committed successfully';
  } catch (e) {
    gitResult = `Git error: ${e.message}`;
  }
} else {
  gitResult = 'Skipped â€” TSC errors found';
}

return [{ json: { results, filesWritten, tscResult, gitResult } }];
